The booking detail modal (6pa.6.11) should have an "Ajouter au calendrier" CTA that downloads an .ics file. iOS/Android both natively handle .ics — tapping it on a phone opens the OS calendar app with the event pre-filled. This is a high-leverage UX win for almost zero implementation cost.

# Scope

Add a helper in `mobile-app/api.js` (or new `mobile-app/calendar.js`):

```js
window.EwashCalendar = {
  generateIcs: function (booking) {
    var dtStart = _parseToIcs(booking.date_label, booking.slot_label);
    var dtEnd = _addHours(dtStart, 2);  // 2-hour slot windows
    var summary = "Ewash · " + booking.service_label;
    var location = booking.location_label;
    var description = "Ref: " + booking.ref + "\\nVéhicule: " + booking.vehicle_label + "\\nTotal: " + booking.total_price_dh + " DH";
    var lines = [
      "BEGIN:VCALENDAR",
      "VERSION:2.0",
      "PRODID:-//Ewash//Booking//FR",
      "BEGIN:VEVENT",
      "UID:" + booking.ref + "@ewash",
      "DTSTAMP:" + _now(),
      "DTSTART;TZID=Africa/Casablanca:" + dtStart,
      "DTEND;TZID=Africa/Casablanca:" + dtEnd,
      "SUMMARY:" + _escape(summary),
      "LOCATION:" + _escape(location),
      "DESCRIPTION:" + _escape(description),
      "STATUS:" + (_isConfirmed(booking.status) ? "CONFIRMED" : "TENTATIVE"),
      "BEGIN:VALARM",
      "TRIGGER:-PT2H",  // 2 hours before — matches the H-2 reminder
      "ACTION:DISPLAY",
      "DESCRIPTION:Préparez votre véhicule pour le lavage Ewash dans 2h",
      "END:VALARM",
      "END:VEVENT",
      "END:VCALENDAR",
    ];
    return lines.join("\\r\\n");
  },

  download: function (booking, locale) {
    var ics = window.EwashCalendar.generateIcs(booking);
    var blob = new Blob([ics], { type: "text/calendar;charset=utf-8" });
    var url = URL.createObjectURL(blob);
    var a = document.createElement("a");
    a.href = url;
    a.download = "ewash-" + booking.ref + ".ics";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(function () { URL.revokeObjectURL(url); }, 0);
    EwashLog.info("calendar.export", { ref: booking.ref, status: booking.status });
  },
};

// _parseToIcs: takes "Lundi 20 mai 2026" + "09:00 - 11:00" → "20260520T090000"
// _addHours: adds hours to ICS timestamp
// _now: returns current time in UTC ICS format "20260514T120000Z"
// _escape: escapes characters per RFC 5545 (commas, semicolons, backslashes, newlines)
```

