# Context

The fetch wrapper that every PWA component uses to talk to the backend. Lives on `window.EwashAPI` to match the project's zero-build global-namespace convention used by `components.jsx`, `screens.jsx`, etc. (See `app.jsx` `Object.assign(window, { App })` pattern.)

# Scope — core helper

Create `mobile-app/api.js`:

```js
(function () {
  var TOKEN_KEY = "ewash.bookings_token";
  var PHONE_KEY = "ewash.phone";
  var DEFAULT_TIMEOUT_MS = 10000;

  function _base() {
    return window.EWASH_API_BASE || "";
  }

  async function _fetch(path, { method = "GET", headers = {}, body = null, timeout = DEFAULT_TIMEOUT_MS } = {}) {
    var controller = new AbortController();
    var t = setTimeout(function () { controller.abort(); }, timeout);
    var url = _base() + path;
    var t0 = performance.now();
    try {
      var resp = await fetch(url, {
        method,
        headers: Object.assign({ "Accept": "application/json", "Content-Type": "application/json" }, headers),
        body: body !== null ? JSON.stringify(body) : null,
        signal: controller.signal,
        mode: "cors",
      });
      var dt = (performance.now() - t0).toFixed(0);
      if (!resp.ok) {
        var errBody = await resp.json().catch(function () { return { error_code: "non_json", message: resp.statusText }; });
        var err = new Error(errBody.message || resp.statusText);
        err.error_code = errBody.error_code || "http_" + resp.status;
        err.status = resp.status;
        err.duration_ms = +dt;
        console.warn("[ewash.api]", method, path, "→", resp.status, errBody.error_code, dt + "ms");
        throw err;
      }
      console.info("[ewash.api]", method, path, "→", resp.status, dt + "ms");
      if (resp.status === 204 || resp.status === 304) return null;
      return await resp.json();
    } finally {
      clearTimeout(t);
    }
  }

  window.EwashAPI = {
    _fetch: _fetch,
    _TOKEN_KEY: TOKEN_KEY,
    _PHONE_KEY: PHONE_KEY,
    // populated by subsequent beads
  };
})();
```

