```js
function _getToken() {
  try { return localStorage.getItem(TOKEN_KEY) || ""; } catch (e) { return ""; }
}
function _saveToken(t) {
  if (!t) return;
  try { localStorage.setItem(TOKEN_KEY, t); } catch (e) { /* private mode etc */ }
}
function _savePhone(p) {
  if (!p) return;
  try { localStorage.setItem(PHONE_KEY, p); } catch (e) {}
}

async function getBootstrap({ category, promo } = {}) {
  var qs = new URLSearchParams();
  if (category) qs.set("category", category);
  if (promo) qs.set("promo", promo);
  return await _fetch("/api/v1/bootstrap?" + qs.toString());
}

async function validatePromo({ code, category }) {
  return await _fetch("/api/v1/promos/validate", {
    method: "POST",
    body: { code, category },
  });
}

async function submitBooking(payload) {
  // Auto-inject existing token from localStorage so the server can echo it back
  var token = _getToken();
  var fullBody = Object.assign({}, payload, token ? { bookings_token: token } : {});
  var response = await _fetch("/api/v1/bookings", { method: "POST", body: fullBody });
  // Server returns the canonical token (echoed or freshly minted); save it.
  if (response && response.bookings_token) _saveToken(response.bookings_token);
  if (payload.phone) _savePhone(payload.phone);
  return response;
}

async function getMyBookings() {
  var token = _getToken();
  if (!token) {
    var err = new Error("No bookings_token in localStorage");
    err.error_code = "no_local_token";
    throw err;
  }
  return await _fetch("/api/v1/bookings", { headers: { "X-Ewash-Token": token } });
}

Object.assign(window.EwashAPI, { getBootstrap, validatePromo, submitBooking, getMyBookings, _getToken });
